// Messy on purpose: var, ==, unused vars, string concat. Behaviour must be preserved.
var TAX = 0.1;

function total(items) {
  var sum = 0;
  var unused = 'leftover';
  for (var i = 0; i < items.length; i++) {
    sum = sum + items[i].price * items[i].qty;
  }
  return sum;
}

function withTax(items) {
  var t = total(items);
  return t + t * TAX;
}

function label(order) {
  if (order.status == 'paid') {
    return 'Order ' + order.id + ' (' + order.status + ')';
  }
  return 'Order ' + order.id + ' (pending)';
}

function isEmpty(items) {
  if (items.length == 0) {
    return true;
  } else {
    return false;
  }
}

module.exports = { TAX, total, withTax, label, isEmpty };

