const { total, withTax, label, isEmpty } = require('../src/orders');

const cart = [
  { price: 10, qty: 2 },
  { price: 5, qty: 1 },
];

test('total sums price*qty', () => {
  expect(total(cart)).toBe(25);
});
test('withTax adds 10%', () => {
  expect(withTax(cart)).toBeCloseTo(27.5);
});
test('label reflects paid status', () => {
  expect(label({ id: 7, status: 'paid' })).toBe('Order 7 (paid)');
});
test('label falls back to pending', () => {
  expect(label({ id: 8, status: 'new' })).toBe('Order 8 (pending)');
});
test('isEmpty true on empty cart', () => {
  expect(isEmpty([])).toBe(true);
  expect(isEmpty(cart)).toBe(false);
});

